#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
char a[1024][2048];
int n,length=4,k=1;
int main(void){scanf("%d",&n);
    for(int i=0;i<1024;++i)
        for(int j=0;j<2048;++j)a[i][j]=' ';
    a[0][0]=a[1][1]='/',a[0][1]=a[0][2]='_',a[0][3]=a[1][2]='\\';
    while(k<n){
        for(int i=0;i<length>>1;++i)
            for(int j=0;j<length;++j)
                a[i+(length>>1)][j+(length>>1)]=a[i][j+length]=a[i][j];
        length<<=1,++k;
    }for(int i=(length/2)-1;i>=0;--i){
    	for(int j=0;j<length;++j)putchar(a[i][j]);
    	putchar('\n');
	}
        
    return false;
}
